import React from 'react';

const Zoom = ({ onClose }) => {
  return (
    <div className="zoom-container">
      <h1>Zoom Integration</h1>
      <p>Zoom is now active. You can start or join meetings directly from this interface.</p>
      <button onClick={onClose}>Close Zoom</button>
    </div>
  );
};

export default Zoom;
